CREATE TABLE "ShopSettings" ("shop" TEXT NOT NULL, "locale" TEXT NOT NULL DEFAULT 'it', "plan" TEXT NOT NULL DEFAULT 'free', "carbonPricePerKg" DOUBLE PRECISION NOT NULL DEFAULT 0.30, "carbonNeutralEnabled" BOOLEAN NOT NULL DEFAULT false, "checkoutBadgeEnabled" BOOLEAN NOT NULL DEFAULT true, "defaultCarrier" TEXT NOT NULL DEFAULT 'standard', "monthlyOrderLimit" INTEGER NOT NULL DEFAULT 100, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "ShopSettings_pkey" PRIMARY KEY ("shop"));
CREATE TABLE "SustainabilityOrder" ("id" TEXT NOT NULL, "shop" TEXT NOT NULL, "orderGid" TEXT NOT NULL, "orderName" TEXT, "countryCode" TEXT, "postalCodePrefix" TEXT, "weightGrams" INTEGER NOT NULL, "distanceKm" DOUBLE PRECISION NOT NULL, "emissionsKg" DOUBLE PRECISION NOT NULL, "baselineEmissionsKg" DOUBLE PRECISION NOT NULL, "savingsKg" DOUBLE PRECISION NOT NULL DEFAULT 0, "carrier" TEXT NOT NULL, "packagingCode" TEXT NOT NULL, "offsetSelected" BOOLEAN NOT NULL DEFAULT false, "offsetAmount" DOUBLE PRECISION NOT NULL DEFAULT 0, "calculatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "SustainabilityOrder_pkey" PRIMARY KEY ("id"), CONSTRAINT "SustainabilityOrder_shop_fkey" FOREIGN KEY ("shop") REFERENCES "ShopSettings" ("shop") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "ProductStat" ("id" TEXT NOT NULL, "orderId" TEXT NOT NULL, "productGid" TEXT, "title" TEXT NOT NULL, "category" TEXT, "quantity" INTEGER NOT NULL, "allocatedEmissionsKg" DOUBLE PRECISION NOT NULL, CONSTRAINT "ProductStat_pkey" PRIMARY KEY ("id"), CONSTRAINT "ProductStat_orderId_fkey" FOREIGN KEY ("orderId") REFERENCES "SustainabilityOrder" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "WebhookReceipt" ("id" TEXT NOT NULL, "topic" TEXT NOT NULL, "shop" TEXT NOT NULL, "receivedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "WebhookReceipt_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "SustainabilityOrder_shop_orderGid_key" ON "SustainabilityOrder"("shop", "orderGid");
CREATE INDEX "SustainabilityOrder_shop_calculatedAt_idx" ON "SustainabilityOrder"("shop", "calculatedAt");
CREATE INDEX "ProductStat_productGid_idx" ON "ProductStat"("productGid");
